changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.document_aspects        TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.document_aspects_id_seq                 TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.document_highlights     TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.document_highlights_id_seq              TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.aspect_extraction_queue TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.aspect_extraction_queue_id_seq          TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.aspect_promotion_log    TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.aspect_promotion_log_id_seq             TO nexus_svc';
        RAISE NOTICE 'Granted aspects table privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants';
    END IF;
END
$$;
